public class Main {
    public static void main(String[] args) {
        RideService svc = new RideService();
        Location a = new Location(40.0, -74.0, "A");
        Location b = new Location(40.5, -74.0, "B");
        Driver d1 = new Driver("D1", "Bob", "Economy", "P1", new Location(40.0, -74.0, "Near"));
        svc.registerDriver(d1);
        Rider r = new Rider("R1", "Alice", "555", a);
        Trip t = svc.requestRide(r, a, b);
        boolean before = !d1.isAvailable();
        svc.cancelTrip(t);
        if (before && d1.isAvailable() && t.getState() == TripState.CANCELLED) System.out.println("CANCEL_OK");
    }
}

