public class Main {
    public static void main(String[] args) {
        RideService svc = new RideService();
        Location a = new Location(40.0, -74.0, "A");
        Driver near = new Driver("D1", "Bob", "Economy", "P1", new Location(40.001, -74.0, "VeryNear"));
        Driver far = new Driver("D2", "Carol", "Economy", "P2", new Location(40.05, -74.0, "Far"));
        far.addRating(5.0); far.addRating(5.0);
        near.addRating(3.0);
        svc.registerDriver(near);
        svc.registerDriver(far);
        svc.setMatchingStrategy(new HighestRatedStrategy(20.0));
        Rider r = new Rider("R1", "Alice", "555", a);
        Trip t = svc.requestRide(r, a, new Location(40.5, -74.0, "B"));
        if (t.getDriver() == far) System.out.println("HIGHEST_RATED_OK");
    }
}
